UPDATE requirement
function_name = #{functionName}, module_name = #{moduleName}, request_department = #{requestDepartment}, request_owner = #{requestOwner}, product_owner = #{productOwner}, priority = #{priority}, planned_start_time = #{plannedStartTime}, planned_end_time = #{plannedEndTime}, actual_start_time = #{actualStartTime}, actual_end_time = #{actualEndTime}, status = #{status}, description = #{description}, expected_online_date = #{expectedOnlineDate}, submission_status = #{submissionStatus}, submitted_by = #{submittedBy},
WHERE id = #{id}

mapper.select:
SELECT priority AS name, COUNT(*) AS value FROM requirement WHERE (submission_status = '进入需求池' OR submission_status IS NULL) AND priority IS NOT NULL AND priority != ''
AND request_department = #{department}
GROUP BY priority

SELECT status AS name, COUNT(*) AS value FROM requirement WHERE (submission_status = '进入需求池' OR submission_status IS NULL)
AND request_department = #{department}
GROUP BY status

SELECT COUNT(*) FROM requirement
WHERE function_name = #{functionName}
AND id != #{excludeId}

SELECT * FROM requirement
WHERE submission_status IS NOT NULL

    AND function_name LIKE CONCAT('%', #{functionName}, '%')


    AND module_name = #{moduleName}


    AND request_department = #{requestDepartment}


    AND request_owner LIKE CONCAT('%', #{requestOwner}, '%')


    AND product_owner = #{productOwner}


    AND submission_status = #{submissionStatus}


    AND priority IN

        #{p}



    AND submitted_by = #{submittedBy}


    ORDER BY request_department ASC
    ORDER BY request_department DESC
    ORDER BY request_owner ASC
    ORDER BY request_owner DESC
    ORDER BY CASE priority WHEN '紧急' THEN 1 WHEN '高' THEN 2 WHEN '中' THEN 3 WHEN '低' THEN 4 ELSE 5 END ASC
    ORDER BY CASE priority WHEN '紧急' THEN 1 WHEN '高' THEN 2 WHEN '中' THEN 3 WHEN '低' THEN 4 ELSE 5 END DESC
    ORDER BY CASE submission_status WHEN '已创建' THEN 1 WHEN '待评估' THEN 2 WHEN '已驳回' THEN 3 WHEN '进入需求池' THEN 4 WHEN '已取消' THEN 5 ELSE 6 END ASC
    ORDER BY CASE submission_status WHEN '已创建' THEN 1 WHEN '待评估' THEN 2 WHEN '已驳回' THEN 3 WHEN '进入需求池' THEN 4 WHEN '已取消' THEN 5 ELSE 6 END DESC
    ORDER BY created_at DESC

SELECT submission_status AS name, COUNT(*) AS value FROM requirement WHERE submission_status IS NOT NULL
AND submitted_by = #{submittedBy}
GROUP BY submission_status
